import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Types","description":"","frontmatter":{},"headers":[],"relativePath":"language/core_concepts/data_types.md","filePath":"language/core_concepts/data_types.md"}'),n={name:"language/core_concepts/data_types.md"};function o(d,e,r,l,c,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h1><p>Bliss is statically typed. Every value has a type, and that type is always explicitly declared. There are no implicit conversions — a value of one type can never be used where another type is expected.</p><h2 id="scalar-types" tabindex="-1">Scalar Types <a class="header-anchor" href="#scalar-types" aria-label="Permalink to &quot;Scalar Types&quot;">​</a></h2><p>Scalar types hold a single value.</p><h3 id="integers" tabindex="-1">Integers <a class="header-anchor" href="#integers" aria-label="Permalink to &quot;Integers&quot;">​</a></h3><p>Bliss provides both signed and unsigned integers across four sizes:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>i8</code>, <code>i16</code>, <code>i32</code>, <code>i64</code></td><td>Signed integers</td></tr><tr><td><code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code></td><td>Unsigned integers</td></tr></tbody></table><p>The number denotes the bit width. A signed integer can represent negative values, an unsigned integer cannot.</p><h3 id="floating-point" tabindex="-1">Floating Point <a class="header-anchor" href="#floating-point" aria-label="Permalink to &quot;Floating Point&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>f32</code></td><td>32-bit floating point</td></tr><tr><td><code>f64</code></td><td>64-bit floating point</td></tr></tbody></table><h3 id="boolean" tabindex="-1">Boolean <a class="header-anchor" href="#boolean" aria-label="Permalink to &quot;Boolean&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Valid Values</th></tr></thead><tbody><tr><td><code>bool</code></td><td><code>true</code>, <code>false</code></td></tr></tbody></table><h3 id="void" tabindex="-1">Void <a class="header-anchor" href="#void" aria-label="Permalink to &quot;Void&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>void</code></td><td>Represents the absence of a meaningful value</td></tr></tbody></table><p><code>void</code> is a valid type in Bliss. A function that returns nothing has a return type of <code>void</code>. It can be declared as a type annotation, though a <code>void</code> value carries no data.</p><h2 id="composite-types" tabindex="-1">Composite Types <a class="header-anchor" href="#composite-types" aria-label="Permalink to &quot;Composite Types&quot;">​</a></h2><h3 id="arrays" tabindex="-1">Arrays <a class="header-anchor" href="#arrays" aria-label="Permalink to &quot;Arrays&quot;">​</a></h3><p>An array holds a fixed sequence of values of the same type. Arrays cannot be resized once created.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let scores: u8[] = [ 10, 20, 30 ];   // initialized with values</span></span>
<span class="line"><span>let buffer: u8[256];                  // pre-defined fixed size</span></span></code></pre></div><p><code>Type[]</code> is a valid type annotation throughout the language. <code>Type[size]</code> additionally constrains the array to a specific size. The implications of size mismatches in certain contexts are covered in the Functions section.</p><h3 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h3><p><code>data</code> is the only composite type in Bliss. It groups named, typed fields into a single structure.</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data User {</span></span>
<span class="line"><span>    name: u8[],</span></span>
<span class="line"><span>    age: u8</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>data</code> types are covered in full in the Data section.</p><h2 id="strings" tabindex="-1">Strings <a class="header-anchor" href="#strings" aria-label="Permalink to &quot;Strings&quot;">​</a></h2><p>Bliss has no dedicated string type. A string literal is syntactic sugar for a <code>u8[]</code> array:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Hello&quot;</span><span>  // sugar for [ &#39;H&#39;, &#39;e&#39;, &#39;l&#39;, &#39;l&#39;, &#39;o&#39; ]</span></span></code></pre></div><p><code>u8[]</code> is therefore the natural type for text in Bliss.</p><h2 id="type-strictness" tabindex="-1">Type Strictness <a class="header-anchor" href="#type-strictness" aria-label="Permalink to &quot;Type Strictness&quot;">​</a></h2><p>Bliss enforces strict type compatibility. A value of one type cannot be used where another type is expected — even between types of the same family:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32 = 5;</span></span>
<span class="line"><span>let y: i64 = x;  // ❌ invalid — i32 is not i64</span></span></code></pre></div><p>Type conversion will be introduced in a later revision of the language.</p>`,32)])])}const b=a(n,[["render",o]]);export{u as __pageData,b as default};
